/* ---------- helpers ---------- */
const todayStr = () => new Date().toISOString().slice(0, 10);
const uid = () => Math.random().toString(36).slice(2, 9);
const omr = (n) => (Number(n) || 0).toLocaleString("en-US", { minimumFractionDigits: 3, maximumFractionDigits: 3 }) + " OMR";
const daysSince = (d) => (!d ? Infinity : Math.floor((Date.now() - new Date(d).getTime()) / 86400000));
const normPhone = (v) => String(v || "").replace(/[^0-9]/g, "").replace(/^968/, "").replace(/^0+/, "");
const normType = (v, def) => { const s = String(v || "").trim().toLowerCase(); if (!s) return def; if (s.includes("free") || s.includes(tr("فري"))) return "Freelancer"; if (s.includes("full") || s.includes(tr("فول")) || s.includes(tr("ثابت")) || s.includes(tr("دوام"))) return "Full Time"; return def; };
const lastDays = (n) => { const a = []; for (let i = 0; i < n; i++) { const d = new Date(); d.setDate(d.getDate() - i); a.push(d.toISOString().slice(0, 10)); } return a; };

/* earnings owed to a rider (company pays rider), based on TOTAL monthly orders */
function computeEarn(company, type, orders) {
  if (company === "Snoonu") return type === "Full Time" ? 425 : orders * 1.4;
  if (company === "Aramex") {
    if (type === "Full Time") return orders >= 300 ? 400 + (orders - 300) * 0.7 : 200 + orders * 0.6;
    return orders * 0.7;
  }
  return 0; // Talabat: settled by platform, not tracked here
}

/* 6-way bank reconciliation classification */
function classifyTransfer(t, bank) {
  if (!bank || bank.length === 0)
    return { code: "pending", label: "بانتظار كشف البنك", emoji: "⏳", color: "#d97706", status: "Pending" };
  const eq = (a, b) => Math.abs((Number(a) || 0) - (Number(b) || 0)) < 0.001;
  const ref = String(t.reference || "").trim();
  const exact = bank.find((b) => String(b.reference).trim() === ref && ref !== "");
  if (exact) {
    if (eq(exact.amount, t.amount)) {
      if (exact.date && t.date && exact.date !== t.date)
        return { code: "date_diff", label: "يحتاج مراجعة (اختلاف تاريخ)", emoji: "⚠️", color: "#d97706", status: "Review" };
      return { code: "ok", label: "تحويل صحيح", emoji: "✅", color: "#0f9d58", status: "Approved" };
    }
    return { code: "amount_diff", label: "اختلاف في مبلغ التحويل", emoji: "⚠️", color: "#d97706", status: "Review" };
  }
  const amtHit = bank.find((b) => eq(b.amount, t.amount));
  if (amtHit)
    return { code: "ref_diff", label: "اختلاف في الرقم المرجعي", emoji: "⚠️", color: "#d97706", status: "Review" };
  if (!ref || ref.length < 4)
    return { code: "suspect", label: "احتمال إشعار غير صحيح", emoji: "⚠️", color: "#c0341d", status: "Review" };
  return { code: "not_found", label: "لم يتم العثور على التحويل", emoji: "❌", color: "#c0341d", status: "Rejected" };
}

