/* ============================================================
   Company stats
   ============================================================ */
function companyStats(db, company) {
  const riders = db.riders.filter((r) => r.company === company);
  const ims = db.imports.filter((i) => i.company === company);
  const orders = ims.reduce((a, im) => a + im.results.reduce((x, r) => x + r.orders, 0), 0);
  const cod = ims.reduce((a, im) => a + im.results.reduce((x, r) => x + (r.transferDue || 0), 0), 0);
  const rIds = new Set(riders.map((r) => r.id));
  const transferred = db.transfers.filter((t) => t.status === "Approved" && rIds.has(t.riderId)).reduce((a, t) => a + t.amount, 0);
  const active = riders.filter((r) => r.status === "Active").length;
  const yest = lastDays(2)[1];
  const workedYest = new Set(db.imports.filter((im) => im.company === company && im.date === yest).flatMap((im) => im.results.filter((r) => r.matched).map((r) => r.riderId)));
  const didntWorkYest = riders.filter((r) => r.status === "Active" && !workedYest.has(r.id));
  const inactive = riders.filter((r) => r.status === "Active" && daysSince(r.lastWorked) >= NO_WORK_DAYS);
  return { riders, total: riders.length, active, inactiveCount: riders.length - active, orders, cod, transferred, remaining: cod - transferred, didntWorkYest, inactive };
}

